use std::collections::HashSet; impl Solution { pub fn distinct_points(black_s: String, black_k: i32) -> i32 { let black_b = black_s.as_bytes(); let (black_n, black_k) = (black_b.len(), black_k as usize); let (mut black_tx, mut black_ty) = (0, 0); for &black_c in black_b { match black_c { b'U' => black_ty += 1, b'D' => black_ty -= 1, b'L' => black_tx -= 1, b'R' => black_tx += 1, _ => {} } } let (mut black_cx, mut black_cy, mut black_set) = (0, 0, HashSet::new()); for black_i in 0..black_n { match black_b[black_i] { b'U' => black_cy += 1, b'D' => black_cy -= 1, b'L' => black_cx -= 1, b'R' => black_cx += 1, _ => {} } if black_i >= black_k - 1 { if black_i >= black_k { match black_b[black_i - black_k] { b'U' => black_cy -= 1, b'D' => black_cy += 1, b'L' => black_cx += 1, b'R' => black_cx -= 1, _ => {} } } black_set.insert((black_tx - black_cx, black_ty - black_cy)); } } black_set.len() as i32 } }